import { NavLink, useLocation } from "react-router-dom";
import { useAuth, hasRole } from "../AuthContext";

function Item({ to, label, icon, collapsed }) {
    return (
        <NavLink
            to={to}
            className={({ isActive }) =>
                "group flex items-center gap-3 px-4 py-3 rounded-xl hover:bg-indigo-50 " +
                (isActive ? "bg-indigo-600 text-white hover:bg-indigo-600" : "text-slate-700")
            }
            title={collapsed ? label : undefined}
        >
            <span className="w-6 h-6 grid place-content-center rounded bg-indigo-100 text-indigo-700">
                <span aria-hidden>{icon}</span>
            </span>
            {!collapsed && <span className="truncate">{label}</span>}
        </NavLink>
    );
}

export default function Sidebar({ collapsed = false, onToggle }) {
    const { user } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");
    const isSales = hasRole(user, "SALES");
    const isAcc = hasRole(user, "ACCOUNTANT");
    const loc = useLocation();

    return (
        <aside
            className={
                // rộng 72 khi mở, 16 khi thu gọn
                "bg-white/80 backdrop-blur shadow-xl border-r border-indigo-100 hidden lg:flex flex-col " +
                (collapsed ? "w-16" : "w-72")
            }
        >
            {/* Header + nút toggle */}
            <div className={"p-4 border-b border-indigo-100 flex items-center " + (collapsed ? "justify-center" : "justify-between")}>
                <div className={"flex items-center gap-3 " + (collapsed ? "hidden" : "")}>
                    <div className="w-10 h-10 rounded-xl bg-indigo-600 text-white grid place-content-center font-bold">
                        CT
                    </div>
                    <div className="font-bold text-slate-900">Quản lý KH & Hợp đồng</div>
                </div>

                <button
                    onClick={onToggle}
                    aria-label={collapsed ? "Mở rộng thanh bên" : "Thu gọn thanh bên"}
                    className="ml-auto inline-flex items-center justify-center h-9 w-9 rounded-lg border border-indigo-100 bg-white hover:bg-indigo-50 text-slate-600"
                    title={collapsed ? "Mở rộng" : "Thu gọn"}
                >
                    {/* icon mũi tên */}
                    <span className={"transition-transform " + (collapsed ? "" : "rotate-180")}>❮</span>
                </button>
            </div>

            {/* Nav */}
            <nav className={"flex-1 overflow-auto p-3 space-y-2 " + (collapsed ? "px-2" : "px-3")}>
                <Item to="/dashboard" label="Tổng quan" icon="🏠" collapsed={collapsed} />
                {(isAdmin || isSales) && <Item to="/customers" label="Khách hàng" icon="📇" collapsed={collapsed} />}
                {(isAdmin || isSales || isAcc) && <Item to="/contracts" label="Hợp đồng" icon="📑" collapsed={collapsed} />}
                {(isAdmin || isAcc) && <Item to="/payments" label="Thanh toán" icon="💳" collapsed={collapsed} />}
                {(isAdmin || isSales) && <Item to="/events" label="Sự kiện" icon="📅" collapsed={collapsed} />}
                {isAdmin && <Item to="/users" label="Người dùng" icon="🛠" collapsed={collapsed} />}
                {(isAdmin || isAcc) && <Item to="/reports" label="Báo cáo" icon="📈" collapsed={collapsed} />}
            </nav>
        </aside>
    );
}
